# Semantic trigger matching — catches natural language
# ========================================== from .file_reader import read_file
from .api_caller  import call_api TOOLS            = ["file_reader", "system_monitor", "task_manager", "git", "python_sandbox"]
APPROVAL_REQUIRED = ["git", "python_sandbox"] # Wide semantic triggers — catch natural language variations
FILE_TRIGGERS = [
    "read ", "open file", "show file", "read file",
    "cat ", "view file", "load file", "contents of"
] SYSTEM_MONITOR_TRIGGERS = [
    "cpu", "ram", "memory usage", "disk", "system stats",
    "system load", "machine performance", "how slow", "why slow",
    "performance", "usage", "processes", "running apps",
    "how much memory", "how much cpu", "system info"
] TASK_TRIGGERS = [
    "add task", "new task", "my tasks", "show tasks",
    "list tasks", "remind me", "todo", "to do",
    "complete task", "finish task", "task list"
] GIT_TRIGGERS = [
    "git status", "git log", "git commit", "git branch",
    "git diff", "what changed", "show commits", "git info"
] PYTHON_TRIGGERS = [
    "```python", "run python", "execute python",
    "run this code", "run code", "execute code",
    "run script", "python script"
] # System CONTROL — apps, volume, screen
SYSTEM_CONTROL_TRIGGERS = [
    "open app", "close app", "quit app", "launch app",
    "play music", "pause music", "skip song",
    "next song", "previous song",
    "volume up", "volume down", "mute", "unmute",
    "take screenshot", "lock screen",
    "sleep display", "empty trash"
] def detect_tool(user_input: str) -> str | None:
    text = user_input.lower() if any(t in text for t in PYTHON_TRIGGERS):
        return "python_sandbox"
    if any(t in text for t in GIT_TRIGGERS):
        return "git"
    if any(t in text for t in TASK_TRIGGERS):
        return "task_manager"
    if any(t in text for t in SYSTEM_MONITOR_TRIGGERS):
        return "system_monitor"
    if any(t in text for t in FILE_TRIGGERS):
        return "file_reader" def is_system_command(text: str) -> bool:
    return any(t in text.lower() for t in SYSTEM_CONTROL_TRIGGERS) def requires_approval(tool: str) -> bool:
    return tool in APPROVAL_REQUIRED def route_tool(user_text: str):
    text = user_text.lower()
    if text.startswith("read "):
        return read_file(user_text.replace("read ", "").strip())
    if text.startswith("api "):
        return call_api(user_text.replace("api ", "").strip())
    return None

def call_api(url: str):
    try:
        r = requests.get(url, timeout=5)
        return r.text[:1500]  # prevent huge outputs
    except Exception as e:
        return f"API error: {e}"

import subprocess
import logging
from datetime import datetime
from typing import List, Dict, Optional # Only check these calendars — skip India Holidays (too many events)
CALENDARS_TO_CHECK = ["Home", "Work", "Scheduled Reminders"] def _get_all_events(calendar: str) -> List[Dict]:
    """Get all events from a single calendar — fast, no date filter in AppleScript."""
    try:
        script = f'''
tell application "Calendar"
    tell calendar "{calendar}"
        set output to ""
        repeat with e in (every event)
            set output to output & (summary of e) & "|" & ((start date of e) as string) & "||"
        end repeat
        return output
    end tell
end tell
'''
        result = subprocess.run(
            ["osascript", "-e", script],
            capture_output=True, text=True, timeout=10
        )
        raw = result.stdout.strip()
        if not raw:
            return [] events = []
        for item in raw.split("||"):
            item = item.strip()
            if not item:
                continue
            parts = item.split("|")
            if len(parts) >= 2 and parts[0].strip():
                events.append({
                    "title":    parts[0].strip(),
                    "raw_time": parts[1].strip(),
                    "calendar": calendar
                })
        return events
    except Exception as e:
        logger.error(f"Error fetching {calendar}: {e}")
        return [] def _parse_raw_time(raw: str) -> Optional[datetime]:
    """Parse AppleScript date string like 'Tuesday, 3 March 2026 at 8:13:30 PM'"""
    try:
        # Remove day name
        parts = raw.split(", ", 1)
        date_part = parts[1] if len(parts) > 1 else parts[0]
        # Remove 'at'
        date_part = date_part.replace(" at ", " ")
        return datetime.strptime(date_part.strip(), "%d %B %Y %I:%M:%S %p")
    except Exception:
        try:
            return datetime.strptime(raw.strip(), "%A, %d %B %Y at %I:%M:%S %p")
        except Exception:
            return None def get_todays_events() -> List[Dict]:
    today = datetime.now().date()
    events = []
    for cal in CALENDARS_TO_CHECK:
        for e in _get_all_events(cal):
            dt = _parse_raw_time(e["raw_time"])
            if dt and dt.date() == today:
                events.append({
                    "title":    e["title"],
                    "time":     dt.strftime("%I:%M %p").lstrip("0"),
                    "calendar": e["calendar"],
                    "dt":       dt
                })
    events.sort(key=lambda x: x["dt"])
    return events def get_upcoming_events(hours: int = 2) -> List[Dict]:
    now    = datetime.now()
    events = []
    for cal in CALENDARS_TO_CHECK:
        for e in _get_all_events(cal):
            dt = _parse_raw_time(e["raw_time"])
            if dt and now <= dt <= datetime(now.year, now.month, now.day, now.hour, now.minute) \
                    .replace(hour=now.hour) and (dt - now).total_seconds() <= hours * 3600:
                events.append({
                    "title":    e["title"],
                    "time":     dt.strftime("%I:%M %p").lstrip("0"),
                    "calendar": e["calendar"],
                    "dt":       dt
                })
    events.sort(key=lambda x: x["dt"])
    return events def get_next_event() -> Optional[Dict]:
    now    = datetime.now()
    events = []
    for cal in CALENDARS_TO_CHECK:
        for e in _get_all_events(cal):
            dt = _parse_raw_time(e["raw_time"])
            if dt and dt > now:
                events.append({
                    "title":    e["title"],
                    "time":     dt.strftime("%I:%M %p").lstrip("0"),
                    "calendar": e["calendar"],
                    "dt":       dt
                })
    if not events:
        return None
    events.sort(key=lambda x: x["dt"])
    return events[0] def morning_briefing_text(user_name: str = "Arnav") -> str:
    events = get_todays_events()
    hour   = datetime.now().hour
    greeting = "Good morning" if hour < 12 else "Good afternoon" if hour < 17 else "Good evening" if not events:
        return f"{greeting}, {user_name}. No events on your calendar today. Clear day ahead." msg = f"{greeting}, {user_name}. You have {len(events)} event{'s' if len(events) > 1 else ''} today. "
    for i, e in enumerate(events[:3]):
        msg += f"{'First up' if i == 0 else 'Then'}: {e['title']} at {e['time']}. "
    if len(events) > 3:
        msg += f"And {len(events) - 3} more."
    return msg def reminder_check_text(user_name: str = "Arnav") -> Optional[str]:
    now    = datetime.now()
    events = []
    for cal in CALENDARS_TO_CHECK:
        for e in _get_all_events(cal):
            dt = _parse_raw_time(e["raw_time"])
            if dt and 0 <= (dt - now).total_seconds() <= 3600:
                events.append({"title": e["title"], "dt": dt})
    if not events:
        return None
    events.sort(key=lambda x: x["dt"])
    e    = events[0]
    mins = int((e["dt"] - now).total_seconds() / 60)
    if mins <= 0:
        return f"Hey {user_name}, {e['title']} is happening right now."
    elif mins <= 10:
        return f"Hey {user_name}, {e['title']} starts in {mins} minutes. Get ready."
    elif mins <= 30:
        return f"{user_name}, heads up — {e['title']} in {mins} minutes."
    return None

def handle_calendar_command(text: str, user_name: str = "Arnav") -> Optional[str]:
    t = text.lower()
    if any(w in t for w in ["today's events", "my schedule", "what's on today",
                             "calendar", "my meetings", "my day", "what do i have"]):
        events = get_todays_events()
        if not events:
            return "Nothing on your calendar today."
        reply = f"You have {len(events)} event{'s' if len(events) > 1 else ''} today: "
        for e in events[:4]:
            reply += f"{e['title']} at {e['time']}, "
        return reply.rstrip(", ") + "." if any(w in t for w in ["next meeting", "next event", "what's next"]):
        event = get_next_event()
        if not event:
            return "No upcoming events."
        return f"Your next event is {event['title']} at {event['time']}." if __name__ == "__main__":
    print("📅 Testing Calendar Tool...")
    print("\nToday's events:")
    events = get_todays_events()
    if events:
        for e in events:
            print(f"  • {e['title']} at {e['time']} ({e['calendar']})")
    else:
        print("  No events today")
    print("\nMorning briefing:")
    print(morning_briefing_text())
    print("\nNext event:")
    e = get_next_event()
    print(f"  {e['title']} at {e['time']}" if e else "  None")

import logging
import re
from typing import Optional
from ddgs import DDGS def search_web(query: str, max_results: int = 5) -> str:
    try:
        with DDGS() as ddgs:
            results = list(ddgs.text(query, max_results=max_results, region="us-en"))
        if not results:
            return f"No results found for '{query}'."
        lines = [f"Search: **{query}**\n"]
        for i, r in enumerate(results[:3], 1):
            lines.append(f"{i}. **{r.get('title','')}**")
            lines.append(f"   {r.get('body','')[:220]}")
            lines.append(f"   {r.get('href','')}\n")
        return "\n".join(lines)
    except Exception as e:
        return f"Search failed: {e}" def search_news(query: str, max_results: int = 5) -> str:
    try:
        with DDGS() as ddgs:
            results = list(ddgs.news(query, max_results=max_results, region="us-en"))
        if not results:
            return f"No news found for '{query}'."
        lines = [f"Latest news: **{query}**\n"]
        for i, r in enumerate(results[:3], 1):
            date = r.get("date","")[:10] if r.get("date") else ""
            lines.append(f"{i}. **{r.get('title','')}** ({date})")
            lines.append(f"   {r.get('body','')[:200]}")
            lines.append(f"   {r.get('url','')}\n")
        return "\n".join(lines)
    except Exception as e:
        return f"News search failed: {e}" def search_quick(query: str) -> str:
    try:
        with DDGS() as ddgs:
            results = list(ddgs.text(query, max_results=3, region="us-en"))
        if not results:
            return search_web(query)
        top  = results[0]
        body = top.get("body", "")[:400]
        ans  = _best_sentence(query, body)
        return f"{ans}\nSource: {top.get('title','')}\n{top.get('href','')}"
    except Exception as e:
        return search_web(query) def _best_sentence(query: str, text: str) -> str:
    if not text:
        return text
    sentences  = text.replace("\n", " ").split(". ")
    query_words = set(query.lower().split())
    best, best_score = text[:300], 0
    for s in sentences:
        score = sum(1 for w in query_words if w in s.lower())
        if score > best_score:
            best_score = score
            best = s
    return best.strip() def handle_search_command(text: str) -> Optional[str]:
    t = text.lower().strip() # ── News ──────────────────────────────────────────────────
    if any(w in t for w in ["news about", "latest news", "recent news", "what's happening", "headlines"]):
        query = t
        for p in ["news about", "latest news on", "latest news about", "recent news on", "what's happening with", "headlines on"]:
            query = query.replace(p, "").strip()
        return search_news(query or t) # ── Factual with "and" — split into multiple searches ─────
    KEYWORDS = ["ceo", "founder", "president", "capital", "owner", "price", "cto", "age"]
    kw_match  = re.search(r"(ceo|founder|president|capital|owner|price|cto|age) of", t) if kw_match and " and " in t:
        kw      = kw_match.group(1)
        # extract everything after "X of "
        after   = t[t.index(kw_match.group(0)) + len(kw_match.group(0)):].strip()
        entities = [e.strip() for e in after.split(" and ") if e.strip()]
        results  = []
        for entity in entities:
            r = search_quick(f"{kw} of {entity}")
            if r:
                results.append(f"**{entity.title()}:** {r}")
        if results:
            return "\n\n".join(results) # ── Single factual question ────────────────────────────────
    factual_starts = ["who is ", "what is ", "when is ", "where is ", "how much ",
                      "what are ", "who are ", "which is ", "how many ", "when was ", "what was "]
    factual_contains = [" ceo of ", " founder of ", " president of ", " capital of ",
                        " population of ", " age of ", " cto of ", " owner of ", " price of "] if (any(t.startswith(w) for w in factual_starts)
            or any(w in t for w in factual_contains)
            or (kw_match and len(t.split()) <= 6)):
        return search_quick(t) # ── Explicit search ────────────────────────────────────────
    if any(w in t for w in ["search ", "search for ", "look up ", "google ", "find info", "find out"]):
        query = t
        for p in ["search for ", "search ", "look up ", "google ", "find info on ", "find info about ", "find out about "]:
            query = query.replace(p, "").strip()
        return search_web(query) if __name__ == "__main__":
    print("=== ceo of apple and google ===")
    print(handle_search_command("ceo of apple and google"))
    print("\n=== who is the PM of india ===")
    print(handle_search_command("who is the PM of india"))
    print("\n=== latest news AI ===")
    print(handle_search_command("latest news AI"))

import json
