EPISODES_FILE = os.path.join(_BACKEND_DIR, "memory", "data", "episodes.json")
PATTERNS_FILE = os.path.join(_BACKEND_DIR, "memory", "data", "patterns.json") def _load_episodes() -> List[Dict]:
    if not os.path.exists(EPISODES_FILE):
        return []
    try:
        with open(EPISODES_FILE) as f:
            return json.load(f)
    except Exception:
        return [] def _load_patterns() -> Dict:
    if not os.path.exists(PATTERNS_FILE):
        return {"topics": {}, "last_session": None, "pending_tasks": []}
    try:
        with open(PATTERNS_FILE) as f:
            return json.load(f)
    except Exception:
        return {"topics": {}, "last_session": None, "pending_tasks": []} def _save_patterns(patterns: Dict) -> None:
    os.makedirs(os.path.dirname(PATTERNS_FILE), exist_ok=True)
    with open(PATTERNS_FILE, "w") as f:
        json.dump(patterns, f, indent=2) def analyze_patterns() -> Dict:
    episodes = _load_episodes()
    if not episodes:
        return {} stop_words = {
        "i", "a", "the", "is", "are", "was", "what", "how", "why",
        "do", "did", "can", "you", "me", "my", "about", "to", "in",
        "of", "and", "or", "for", "with", "it", "this", "that", "be",
        "explain", "tell", "show", "give", "make", "help", "please",
        "would", "could", "should", "does", "have", "has", "will",
        "want", "need", "think", "know", "understand", "using", "use"
    } word_counts: Counter   = Counter()
    intent_counts: Counter = Counter() for ep in episodes[-50:]:
        words = ep.get("user", "").lower().split()
        for w in words:
            w = w.strip(".,?!")
            if len(w) > 4 and w not in stop_words:
                word_counts[w] += 1
        if ep.get("intent"):
            intent_counts[ep["intent"]] += 1 top_topics  = [w for w, _ in word_counts.most_common(5)]
    top_intents = [i for i, _ in intent_counts.most_common(3)] patterns = _load_patterns()
    patterns["topics"]        = dict(word_counts.most_common(10))
    patterns["top_topics"]    = top_topics
    patterns["top_intents"]   = top_intents
    patterns["last_session"]  = datetime.utcnow().isoformat()
    patterns["episode_count"] = len(episodes)
