    # HELPERS
    # ========================================================== def _add_to_history(self, role: str, content: str) -> None:
        self.conversation_history.append({"role": role, "content": content})
        # Persist to SQLite
        if role == "assistant" and len(self.conversation_history) >= 2:
            try:
                from memory_db import save_exchange
                last_user = next((m["content"] for m in reversed(self.conversation_history[:-1]) if m["role"] == "user"), "")
                save_exchange(last_user, content)
            except Exception:
                pass
        if len(self.conversation_history) > 10:
            self.conversation_history = self.conversation_history[-10:] def _store_fact(self, fact: Dict, memory: Dict) -> Dict:
        memory["user_facts"].append(fact)
        ftype   = fact["type"]
        subtype = fact.get("subtype", "")
        value   = fact.get("value") if ftype == "identity":
            memory["preferences"]["name"] = value
        elif ftype == "location":
            memory["preferences"]["location"] = value
        elif ftype == "preference":
            memory["preferences"][subtype] = value
        return memory def _acknowledge_fact(self, fact: Dict) -> str:
        return f"Got it! {fact['fact']}." def _build_reply(
        self, reply: str, emotion: str, intent: str, agent: str,
        tool_used: bool = False, memory_updated: bool = False,
        citations: Optional[List] = None, results_count: int = 0,
        confidence: float = 0.6
    ) -> Dict:
        conf_info: Dict = confidence_label(confidence)
        result: Dict = {
            "reply":            reply,
            "emotion":          emotion,
            "intent":           intent,
            "agent":            agent,
            "tool_used":        tool_used,
            "memory_updated":   memory_updated,
            "confidence":       confidence,
            "confidence_label": conf_info["text"],
            "confidence_emoji": conf_info["emoji"],
        }
        if citations:
            result["citations"]     = citations
            result["results_count"] = results_count
        return result def _error_reply(self, message: str) -> Dict:
        return {
            "reply":            message,
            "emotion":          "neutral",
            "intent":           "error",
            "agent":            "error_handler",
            "tool_used":        False,
            "memory_updated":   False,
            "confidence":       0.0,
            "confidence_label": "UNKNOWN",
            "confidence_emoji": "⚪",
        } def get_model_info(self) -> Dict:
        return self.model_manager.get_model_info()

