# ========================================== _DEEP_REASON_TRIGGERS = [
    "why", "how does", "explain how", "what causes", "difference between",
    "compare", "pros and cons", "should i", "which is better", "analyze",
    "walk me through", "break down", "step by step", "reason", "think"
] _SIMPLE_TRIGGERS = [
    "hi", "hello", "hey", "thanks", "ok", "bye",
    "what's my name", "who am i", "tell me a joke"
] def _needs_deep_reason(text: str) -> bool:
    t = text.lower()
    if any(t.startswith(s) or s == t for s in _SIMPLE_TRIGGERS):
        return False
    return any(trigger in t for trigger in _DEEP_REASON_TRIGGERS) def _basic_clean(text: str) -> str:
    txt = text.strip()
    txt = re.sub(r"\s+", " ", txt)
    if len(txt.split()) == 1 and txt.isalpha():
        return f"Tell me about {txt}."
    if len(txt.split()) <= 2 and "?" in txt:
        topic = txt.replace("?", "").strip()
        return f"Explain {topic} briefly."
    return txt def reason(user_text: str, model: str = "phi3:mini") -> str:
    if not user_text or not user_text.strip():
        return user_text if not _needs_deep_reason(user_text):
        return _basic_clean(user_text) logger.info(f"🧠 Deep reasoning pre-process: {user_text[:60]}...") prompt = f"""You are a query optimizer for an AI assistant. Rewrite the user's question as a clear, structured prompt that will
get the BEST possible answer from an LLM. Rules:
- Keep the core intent exactly the same
- Make it specific and unambiguous
- If multi-part, list parts clearly
- Do NOT answer — only rewrite
- Output ONLY the rewritten query, nothing else try:
        response = ollama.chat(
            model=model,
            messages=[{"role": "user", "content": prompt}],
            options={"temperature": 0.2, "num_predict": 120}
        )
        rewritten = response["message"]["content"].strip() if len(rewritten) < 5 or len(rewritten) > len(user_text) * 8:
            logger.warning("Reasoner output suspicious, using original")
            return _basic_clean(user_text) logger.info(f"✅ Reasoner: {rewritten[:80]}")
        return rewritten except Exception as e:
        logger.warning(f"Reasoner LLM failed ({e}), using basic clean")
        return _basic_clean(user_text)

def _parse_json(text: str) -> Dict:
    """Extract JSON from LLaVA response."""
    # Strip markdown fences
    text = text.strip().strip("```json").strip("```").strip()
    # Try direct parse first
    try:
        return json.loads(text)
    except Exception:
        pass # Try extracting JSON block
    match = re.search(r'\{[\s\S]*\}', text)
    if match:
        try:
            return json.loads(match.group())
        except Exception:
            pass # Fallback — return raw as jarvis_response
    return {
        "summary": "Analysis complete",
        "jarvis_response": text.strip()[:500],
        "suggestions": []
    } def analyze_code_in_image(image_b64: str) -> Dict:
    """Specialized code analysis from screenshot."""
    result = analyze(image_b64, mode="screen") code = result.get("extracted", {}).get("key_text") or result.get("code_found", "")
    error = result.get("extracted", {}).get("error") if error:
        # Ask for specific fix
        try:
            fix_response = ollama.chat(
                model="phi3:mini",
                messages=[{"role": "user", "content": f"Fix this error:\n{error}"}],
                options={"temperature": 0.1, "num_predict": 300}
            )
            result["fix_suggestion"] = fix_response["message"]["content"]
        except Exception:
            pass

# rag/ingest.py — Multi-source document ingestion
import os
from rag.chunker import chunk_text, chunk_by_paragraph
from rag.embeddings import embed_batch
from rag.vector_store import add_chunks def ingest_text(text: str, source: str = "manual", tags: list = None):
    chunks = chunk_by_paragraph(text)
    if not chunks:
        return 0
    embeddings = embed_batch(chunks)
    add_chunks(chunks, embeddings, source=source, tags=tags or [])
    return len(chunks) def ingest_file(path: str, tags: list = None):
    ext = os.path.splitext(path)[1].lower()
    if ext == ".pdf":
        from pypdf import PdfReader
        reader = PdfReader(path)
        text   = "\n".join(p.extract_text() or "" for p in reader.pages)
    elif ext in [".md", ".txt", ".py", ".js", ".ts"]:
        with open(path) as f:
            text = f.read()
    else:
        print(f"Unsupported: {ext}")
        return 0
    source = os.path.basename(path)
    return ingest_text(text, source=source, tags=tags or [ext.strip(".")]) def ingest_folder(folder: str, extensions: list = None, tags: list = None):
    extensions = extensions or [".md", ".txt", ".py", ".pdf"]
    total = 0
    for root, _, files in os.walk(folder):
        for fname in files:
            if any(fname.endswith(ext) for ext in extensions):
                path = os.path.join(root, fname)
                try:
                    n = ingest_file(path, tags=tags)
                    print(f"  ✓ {fname} → {n} chunks")
                    total += n
                except Exception as e:
                    print(f"  ✗ {fname}: {e}")
    return total

# rag/reranker.py — Cross-encoder reranking
_reranker = None def _get_reranker():
    global _reranker
    if _reranker is None:
        from sentence_transformers import CrossEncoder
        _reranker = CrossEncoder("BAAI/bge-reranker-base")
    return _reranker def rerank(query: str, chunks: list[dict], top_k: int = 3) -> list[dict]:
    if not chunks:
        return []
    try:
        reranker = _get_reranker()
        pairs    = [(query, c["text"]) for c in chunks]
        scores   = reranker.predict(pairs)
        for i, chunk in enumerate(chunks):
            chunk["rerank_score"] = float(scores[i])
        reranked = sorted(chunks, key=lambda x: x["rerank_score"], reverse=True)
        return reranked[:top_k]
    except Exception:
        return chunks[:top_k]

# rag/chunker.py — Semantic overlap chunking
import re def chunk_text(text: str, size: int = 500, overlap: int = 100) -> list[str]:
    text = re.sub(r'\s+', ' ', text).strip()
    words = text.split()
    chunks = []
    start = 0
    while start < len(words):
        end = min(start + size, len(words))
        chunk = " ".join(words[start:end])
        if len(chunk.strip()) > 50:
            chunks.append(chunk)
        start += size - overlap
    return chunks def chunk_by_paragraph(text: str, max_size: int = 600) -> list[str]:
    paragraphs = [p.strip() for p in text.split('\n\n') if len(p.strip()) > 50]
    chunks = []
    current = ""
    for para in paragraphs:
        if len((current + " " + para).split()) <= max_size:
            current = (current + " " + para).strip()
        else:
            if current:
                chunks.append(current)
            current = para
    if current:
        chunks.append(current)
    return chunks if chunks else chunk_text(text)

# rag/vector_store.py — FAISS index with metadata
import os
import json
import faiss
import numpy as np
from datetime import datetime STORE_DIR  = os.path.join(os.path.dirname(__file__), "..", "memory", "vector_store")
INDEX_PATH = os.path.join(STORE_DIR, "index.faiss")
META_PATH  = os.path.join(STORE_DIR, "metadata.json")
DIM        = 384 def _load_index():
    if os.path.exists(INDEX_PATH):
        return faiss.read_index(INDEX_PATH)
    return faiss.IndexFlatIP(DIM)  # Inner product for normalized vecs = cosine similarity def _load_meta() -> list:
    if os.path.exists(META_PATH):
        with open(META_PATH) as f:
            return json.load(f)
    return [] def add_chunks(chunks: list[str], embeddings: np.ndarray, source: str, tags: list[str] = None):
    index = _load_index()
    meta  = _load_meta()
    index.add(embeddings.astype(np.float32))
    for chunk in chunks:
        meta.append({
            "text":      chunk,
            "source":    source,
            "tags":      tags or [],
            "timestamp": datetime.now().isoformat()
        })
    faiss.write_index(index, INDEX_PATH)
    with open(META_PATH, "w") as f:
        json.dump(meta, f, indent=2) def search(query_vec: np.ndarray, top_k: int = 5) -> list[dict]:
    index = _load_index()
    meta  = _load_meta()
    if index.ntotal == 0:
        return []
    scores, indices = index.search(query_vec.reshape(1, -1).astype(np.float32), min(top_k, index.ntotal))
    results = []
    for score, idx in zip(scores[0], indices[0]):
        if idx >= 0 and idx < len(meta):
            results.append({**meta[idx], "score": float(score)})
    return results def count() -> int:
    return _load_index().ntotal

# rag/embeddings.py — BGE embeddings with cache
import os
import json
import hashlib
import numpy as np
from sentence_transformers import SentenceTransformer MODEL_NAME  = "BAAI/bge-small-en-v1.5"
CACHE_DIR   = os.path.join(os.path.dirname(__file__), "..", "memory", "embedding_cache")
os.makedirs(CACHE_DIR, exist_ok=True) def get_model() -> SentenceTransformer:
    global _model
    if _model is None:
        _model = SentenceTransformer(MODEL_NAME)
    return _model def _cache_key(text: str) -> str:
    return hashlib.md5(text.encode()).hexdigest() def embed(text: str) -> np.ndarray:
    key = _cache_key(text)
    cache_path = os.path.join(CACHE_DIR, f"{key}.npy")
    if os.path.exists(cache_path):
        return np.load(cache_path)
    vec = get_model().encode(text, normalize_embeddings=True)
    np.save(cache_path, vec)
    return vec def embed_batch(texts: list[str]) -> np.ndarray:
    results = []
    to_encode = []
    indices = []
    cached = {}
    for i, text in enumerate(texts):
        key = _cache_key(text)
        cache_path = os.path.join(CACHE_DIR, f"{key}.npy")
        if os.path.exists(cache_path):
            cached[i] = np.load(cache_path)
        else:
            to_encode.append(text)
            indices.append(i)
    if to_encode:
        vecs = get_model().encode(to_encode, normalize_embeddings=True, batch_size=32)
        for j, i in enumerate(indices):
            np.save(os.path.join(CACHE_DIR, f"{_cache_key(texts[i])}.npy"), vecs[j])
            cached[i] = vecs[j]
    return np.array([cached[i] for i in range(len(texts))])

# rag/rag_engine.py — Main RAG interface
from rag.retriever import hybrid_search
from rag.reranker import rerank
from rag.vector_store import count def query_rag(query: str, top_k: int = 3, use_reranker: bool = True) -> str:
    if count() == 0:
        return ""
    results = hybrid_search(query, top_k=top_k * 2)
    if not results:
        return ""
    if use_reranker and len(results) > 1:
        results = rerank(query, results, top_k=top_k)
    else:
        results = results[:top_k]
    if not results:
        return ""
    context_parts = []
    for r in results:
        source = r.get("source", "unknown")
        text   = r["text"].strip()
        context_parts.append(f"[{source}]\n{text}")
    return "\n\n---\n\n".join(context_parts) def should_use_rag(query: str) -> bool:
    if count() == 0:
        return False
    skip = ["hi", "hello", "hey", "bye", "thanks", "what time", "how are you"]
    q    = query.lower().strip()
    if any(q == s for s in skip):
        return False
    if len(q.split()) < 3:
        return False
    return True

# Optionally run LLM extraction for complex sentences
